def apply(a,ops):
    out=[]; ia=0
    for k,x in ops:
        if k=='keep': assert a[ia]==x; out.append(x); ia+=1
        elif k=='del': assert a[ia]==x; ia+=1
        else: out.append(x)
    assert ia==len(a)
    return out
def lcs(a,b):
    import functools
    @functools.lru_cache(None)
    def f(i,j):
        if i==len(a) or j==len(b): return 0
        if a[i]==b[j]: return 1+f(i+1,j+1)
        return max(f(i+1,j),f(i,j+1))
    return f(0,0)
