def diff_ops(a: list, b: list) -> list:
    m, n = len(a), len(b)

    # Build LCS DP table
    dp = [[0] * (n + 1) for _ in range(m + 1)]
    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if a[i - 1] == b[j - 1]:
                dp[i][j] = dp[i - 1][j - 1] + 1
            else:
                dp[i][j] = max(dp[i - 1][j], dp[i][j - 1])

    # Backtrack from (m, n) to (0, 0) to recover edit script in reverse
    ops = []
    i, j = m, n
    while i > 0 or j > 0:
        if i > 0 and j > 0 and a[i - 1] == b[j - 1]:
            # Characters match: keep
            ops.append(('keep', a[i - 1]))
            i -= 1
            j -= 1
        elif i > 0 and (j == 0 or dp[i - 1][j] >= dp[i][j - 1]):
            # Prefer deletion over insertion when tied (del before ins)
            ops.append(('del', a[i - 1]))
            i -= 1
        else:
            # Insert from b
            ops.append(('ins', b[j - 1]))
            j -= 1

    ops.reverse()
    return ops

